// Check: does last plate always have empty RespinLockedPos? And does union == accumulation across plates (no overlap)?
RQ.forEach((r,i)=>{
  const pq = r.PlateQueue||[];
  const acc = new Set();
  let dup=false;
  pq.forEach((p,pi)=>{
    (p.RespinLockedPos||[]).forEach(pos=>{ if(acc.has(pos)) dup=true; acc.add(pos); });
  });
  const lastEmpty = pq.length? (pq[pq.length-1].RespinLockedPos||[]).length===0 : true;
  console.log(`Round[${i}] plates=${pq.length} unionSize=${acc.size} overlapDup=${dup} lastPlateEmpty=${lastEmpty}`);
});
