1	/**
2	 * @ch Respin 雙層索引純邏輯層自動化測試
3	 * 對象：assets/Script/Respin/RespinPlateLogic.ts（零 cc 依賴，可在 Node 跑）
4	 * 執行：npx ts-node -O '{"module":"commonjs"}' --transpile-only tests/RespinPlateLogic.test.ts
5	 * 涵蓋：[testable] BC-1（旗標投影）, BC-2（雙層推進軌跡）, BC-3（鎖定解碼 fail-loud）
6	 */
7	
8	import {
9	    AdvancePlateCursorPure,
10	    IsGoingToFreePure,
11	    IsGoingToRespinPure,
12	    ResolveLockedEntries,
13	} from '../assets/Script/Respin/RespinPlateLogic';
14	
15	let total = 0;
16	let passed = 0;
17	const failures: string[] = [];
18	
19	function check( name: string, cond: boolean ): void
20	{
21	    total++;
22	    if ( cond )
23	    {
24	        passed++;
25	    }
26	    else
27	    {
28	        failures.push( name );
29	        console.error( `  ✗ ${name}` );
30	    }
31	}
32	
33	function eq( name: string, actual: unknown, expected: unknown ): void
34	{
35	    check( `${name}（得 ${JSON.stringify( actual )}，期 ${JSON.stringify( expected )}）`,
36	        JSON.stringify( actual ) === JSON.stringify( expected ) );
37	}
38	
39	// ============================================================
40	// BC-1：旗標投影語意
41	// ============================================================
42	console.log( '— BC-1 IsGoingToFreePure —' );
43	eq( 'MG 首局多 round 未進 FG → true', IsGoingToFreePure( 0, 2, false ), true );
44	eq( 'FG 進行中（isFreeGame）→ false', IsGoingToFreePure( 0, 2, true ), false );
45	eq( '單局（len=1）→ false', IsGoingToFreePure( 0, 1, false ), false );
46	eq( '非首局 round=1 → false', IsGoingToFreePure( 1, 3, false ), false );
47	eq( 'FG 結束 round=last → false', IsGoingToFreePure( 4, 5, false ), false );
48	eq( '閒置 round=-1 → false', IsGoingToFreePure( -1, 0, false ), false );
49	
50	console.log( '— BC-1 IsGoingToRespinPure —' );
51	eq( 'sub<plateCount-1 → true', IsGoingToRespinPure( 0, 3 ), true );
52	eq( '中間手 sub=1/3 → true', IsGoingToRespinPure( 1, 3 ), true );
53	eq( '末手 sub=2/3 → false', IsGoingToRespinPure( 2, 3 ), false );
54	eq( '單 plate（plateCount=1）→ false', IsGoingToRespinPure( 0, 1 ), false );
55	eq( 'plateCount=0（缺值）→ false', IsGoingToRespinPure( 0, 0 ), false );
56	eq( 'plateCount=-1（異常）→ false', IsGoingToRespinPure( 0, -1 ), false );
57	
58	// ============================================================
59	// BC-2：雙層推進軌跡
60	// RoundQueue 形狀 [{plates:3},{plates:1},{plates:2}]
61	// 自 (-1,0) 連續 Advance 必為 (0,0)→(0,1)→(0,2)→(1,0)→(2,0)→(2,1)→(3,0)
62	// ============================================================
63	console.log( '— BC-2 雙層推進軌跡 —' );
64	{
65	    const plates = [ 3, 1, 2 ];
66	    // 取「當前 round 對應」的 plateCount：round 無效（<0 或越界）→ 0
67	    const plateCountOf = ( round: number ): number =>
68	        ( round >= 0 && round < plates.length ) ? plates[ round ] : 0;
69	
70	    const trajectory: Array<{ round: number; sub: number }> = [];
71	    let cur = { round: -1, sub: 0 };
72	    for ( let i = 0; i < 7; i++ )
73	    {
74	        cur = AdvancePlateCursorPure( cur.round, cur.sub, plateCountOf( cur.round ) );
75	        trajectory.push( cur );
76	    }
77	    eq( '軌跡', trajectory, [
78	        { round: 0, sub: 0 },
79	        { round: 0, sub: 1 },
80	        { round: 0, sub: 2 },
81	        { round: 1, sub: 0 },
82	        { round: 2, sub: 0 },
83	        { round: 2, sub: 1 },
84	        { round: 3, sub: 0 },
85	    ] );
86	}
87	// 單 plate 退化：每次 advance 都換局
88	eq( '單 plate 退化 (0,0)+count1 → (1,0)', AdvancePlateCursorPure( 0, 0, 1 ), { round: 1, sub: 0 } );
89	// 連鎖 plates≥3：中間手只推 sub
90	eq( '連鎖 (0,1)+count4 → (0,2)', AdvancePlateCursorPure( 0, 1, 4 ), { round: 0, sub: 2 } );
91	eq( '連鎖末手 (0,3)+count4 → (1,0)', AdvancePlateCursorPure( 0, 3, 4 ), { round: 1, sub: 0 } );
92	// 從 idle (-1,0) plateCount=0 → (0,0)
93	eq( 'idle (-1,0)+count0 → (0,0)', AdvancePlateCursorPure( -1, 0, 0 ), { round: 0, sub: 0 } );
94	
95	// ============================================================
96	// BC-3：ResolveLockedEntries fail-loud
97	// ============================================================
98	console.log( '— BC-3 ResolveLockedEntries —' );
99	{
100	    // 假解碼器：serverPos 直接編碼 col*10+row，負數視為無法解碼
101	    const decode = ( p: number ): { col: number; row: number } | null =>
102	        p < 0 ? null : { col: Math.floor( p / 10 ), row: p % 10 };
103	
104	    // 正常盤面：col1 row0 = Cash(14) number 100、col2 row1 = Mystery(20) number 0
105	    const plate = [
106	        { Col: [ { Symbol: 0, Number: 0 } ] },                       // col0
107	        { Col: [ { Symbol: 14, Number: 100 } ] },                    // col1: (10) → Cash
108	        { Col: [ { Symbol: 0, Number: 0 }, { Symbol: 20, Number: 0 } ] }, // col2: (21) → Mystery
109	    ];
110	
111	    const r1 = ResolveLockedEntries( plate, [ 10, 21 ], decode );
112	    eq( '正常解碼 2 筆', r1.entries, [
113	        { serverPos: 10, col: 1, row: 0, symbol: 14, number: 100 },
114	        { serverPos: 21, col: 2, row: 1, symbol: 20, number: 0 },
115	    ] );
116	    eq( '正常無 warning', r1.warnings.length, 0 );
117	
118	    // 空陣列 → 空 entries 無 warning
119	    const r2 = ResolveLockedEntries( plate, [], decode );
120	    eq( '空 serverPos → 空 entries', r2.entries.length, 0 );
121	    eq( '空 serverPos → 無 warning', r2.warnings.length, 0 );
122	
123	    // null serverPositions → 空，不 throw
124	    const r3 = ResolveLockedEntries( plate, null, decode );
125	    eq( 'null serverPos → 空 entries', r3.entries.length, 0 );
126	
127	    // 解碼失敗（負數）→ 跳該筆 + warning
128	    const r4 = ResolveLockedEntries( plate, [ -1, 10 ], decode );
129	    eq( '解碼失敗跳過、保留有效', r4.entries.length, 1 );
130	    check( '解碼失敗有 warning', r4.warnings.length === 1 );
131	
132	    // col 越界 → 跳該筆 + warning，不 throw
133	    const r5 = ResolveLockedEntries( plate, [ 90 ], decode ); // col9 不存在
134	    eq( 'col 越界 → 空 entries', r5.entries.length, 0 );
135	    check( 'col 越界有 warning', r5.warnings.length === 1 );
136	
137	    // row 越界（col1 只有 row0）→ 跳該筆 + warning
138	    const r6 = ResolveLockedEntries( plate, [ 15 ], decode ); // col1 row5 不存在
139	    eq( 'row 越界 → 空 entries', r6.entries.length, 0 );
140	    check( 'row 越界有 warning', r6.warnings.length === 1 );
141	
142	    // Number 缺值 → 回 -1
143	    const plateNoNum = [ { Col: [ { Symbol: 14 } ] } ]; // col0 row0 Symbol 但無 Number
144	    const r7 = ResolveLockedEntries( plateNoNum, [ 0 ], decode );
145	    eq( 'Number 缺值回 -1', r7.entries, [ { serverPos: 0, col: 0, row: 0, symbol: 14, number: -1 } ] );
146	
147	    // 不 throw：plateSymbol 為 null
148	    let threw = false;
149	    try { ResolveLockedEntries( null, [ 0 ], decode ); } catch { threw = true; }
150	    check( 'plateSymbol null 不 throw', !threw );
151	}
152	
153	// ============================================================
154	console.log( `\n${passed}/${total} passed` );
155	if ( failures.length > 0 )
156	{
157	    console.error( `\n${failures.length} FAILED:` );
158	    failures.forEach( f => console.error( `  - ${f}` ) );
159	    process.exit( 1 );
160	}
161	console.log( '✅ all passed' );
162

