    CreateSymbolStaticNode(
        col: number,
        row: number,
        symbol: number,
        number: number = -1,
        layer: number = Game_Define.LAYERS.ONE,
        scaleSize: Vec3 = v3( 1, 1, 1 )
    ): Node
    {
        const spriteFrame = this.m_gameView.GetSymbolSpriteFrame( symbol );
        if ( !spriteFrame )
        {
            console.warn( `[EffectPlate] CreateSymbolStaticNode: 找不到 spriteFrame, symbol=${symbol}` );
            return null;
        }

        this.CleanSymbolStatic( col, row, layer );

        const worldPos = this.GetSymbolNodeWorldPos( col, row );

        // 使用 BaseNodePool 取得 static symbol 節點（secondaryType 固定 0）
        if ( !this.m_symbolStaticPrefabs?.[ 0 ] )
        {
            console.warn( `[EffectPlate] CreateSymbolStaticNode: m_symbolStaticPrefabs 未設定，無法建立 static symbol` );
            return null;
        }

        const symbolStaticNode = BaseNodePool.getInstance().GetNode(
            Game_Define.EFFECT_TYPE.STATIC_SYMBOL,
            0,
        );
        symbolStaticNode.name = `StaticSymbol_${col}_${row}`;

        this.m_effectNode[ layer ].addChild( symbolStaticNode );
        symbolStaticNode.setScale( scaleSize );
        symbolStaticNode.setWorldPosition( worldPos );
        symbolStaticNode.active = true;
        tools.SetOrderedZindex( symbolStaticNode, col * 10 + row );

        // 透過 StaticSymbol 元件統一設定 Symbol 圖片、Number Label、底框
